const incoming = $json.body ?? $json;
const alert = incoming.alert ?? incoming;

if (!alert || typeof alert !== 'object') {
  throw new Error('Invalid Wazuh payload: alert object is missing');
}

const rule = alert.rule ?? {};
const agent = alert.agent ?? {};
const data = alert.data ?? {};

// Required fields are checked BEFORE any fallback is applied, so a
// malformed or empty payload is rejected here rather than silently
// passing through as 'unknown'.
const rawEventId = incoming.event_id ?? alert.id;
if (!rawEventId && !agent.id && rule.id === undefined) {
  throw new Error('Malformed Wazuh payload: missing event_id/alert.id, agent.id and rule.id');
}
if (rule.level === undefined || rule.level === null) {
  throw new Error('Malformed Wazuh payload: missing rule.level');
}
if (!agent.name) {
  throw new Error('Malformed Wazuh payload: missing agent.name');
}

const eventId = rawEventId ?? (agent.id ?? 'unknown') + '-' + (rule.id ?? 'unknown') + '-' + (alert.timestamp ?? Date.now());

const level = Number(rule.level);

let severity = 'informational';
if (level >= 12) severity = 'critical';
else if (level >= 10) severity = 'high';
else if (level >= 7) severity = 'medium';
else if (level >= 4) severity = 'low';

const normalized = {
  event_id: String(eventId),
  source: incoming.source ?? 'wazuh',
  sent_at: incoming.sent_at ?? null,
  timestamp: alert.timestamp ?? null,
  level: level,
  severity: severity,
  rule_id: String(rule.id),
  rule_description: rule.description ?? 'No description',
  rule_groups: rule.groups ?? [],
  agent_id: String(agent.id ?? 'unknown'),
  agent_name: agent.name,
  agent_ip: agent.ip ?? null,
  location: alert.location ?? null,
  decoder_name: (alert.decoder ?? {}).name ?? null,
  source_ip: data.srcip ?? data.src_ip ?? null,
  destination_ip: data.dstip ?? data.dst_ip ?? null,
  username: data.srcuser ?? data.dstuser ?? null,
  full_log: alert.full_log ?? null,
  raw_alert: alert
};

return [{ json: normalized }];

function escapeHtml(value) {
  return String(value ?? '')
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#039;');
}

const item = $json;
const sevLabel = (item.severity || 'informational').toUpperCase();
const subject = `[WAZUH][${sevLabel}][L${item.level}][RULE ${item.rule_id}] ${item.agent_name} — ${item.rule_description}`;
const html = `<h2>Wazuh Security Alert</h2>
<table>
  <tr><td><strong>Severity</strong></td><td>${escapeHtml(item.severity)}</td></tr>
  <tr><td><strong>Level</strong></td><td>${escapeHtml(item.level)}</td></tr>
  <tr><td><strong>Event ID</strong></td><td>${escapeHtml(item.event_id)}</td></tr>
  <tr><td><strong>Timestamp</strong></td><td>${escapeHtml(item.timestamp)}</td></tr>
  <tr><td><strong>Rule ID</strong></td><td>${escapeHtml(item.rule_id)}</td></tr>
  <tr><td><strong>Description</strong></td><td>${escapeHtml(item.rule_description)}</td></tr>
  <tr><td><strong>Agent</strong></td><td>${escapeHtml(item.agent_name)}</td></tr>
  <tr><td><strong>Agent IP</strong></td><td>${escapeHtml(item.agent_ip ?? 'Not available')}</td></tr>
  <tr><td><strong>Source IP</strong></td><td>${escapeHtml(item.source_ip ?? 'Not available')}</td></tr>
  <tr><td><strong>Username</strong></td><td>${escapeHtml(item.username ?? 'Not available')}</td></tr>
  <tr><td><strong>Location</strong></td><td>${escapeHtml(item.location)}</td></tr>
</table>
<h3>Original log</h3>
<pre>${escapeHtml(item.full_log ?? 'Not available')}</pre>
<p>This message was generated automatically by the local Wazuh–n8n SOC workflow. Verify the alert in Wazuh Dashboard before taking any response action.</p>`;
return [{ json: { ...item, email_subject: subject, email_html: html } }];
